                    const match = part.match(pattern);
                    if (match && match.index > 0) {
                        company = part.substring(0, match.index).trim();
                        title = match[0].trim();
                        splitDone = true;
                        break;
                    }
                }
                if (!splitDone) {
                    company = part;
                }
                continue;
            }

            // After company, industry/location
